-- ============================================================
-- FreelanceIT — Supabase SQL Setup
-- Colle ce fichier entier dans Supabase → SQL Editor → Run
-- ============================================================

-- ─── 1. Tables Quiz & QuizAttempt ──────────────────────────

CREATE TABLE IF NOT EXISTS "quizzes" (
    "id" TEXT NOT NULL,
    "skill" TEXT NOT NULL,
    "title" TEXT NOT NULL,
    "description" TEXT,
    "difficulty" TEXT NOT NULL DEFAULT 'INTERMEDIATE',
    "questions" TEXT NOT NULL,
    "timeLimit" INTEGER NOT NULL DEFAULT 15,
    "isActive" BOOLEAN NOT NULL DEFAULT true,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "quizzes_pkey" PRIMARY KEY ("id")
);

CREATE UNIQUE INDEX IF NOT EXISTS "quizzes_skill_key" ON "quizzes"("skill");

CREATE TABLE IF NOT EXISTS "quiz_attempts" (
    "id" TEXT NOT NULL,
    "quizId" TEXT NOT NULL,
    "candidateId" TEXT NOT NULL,
    "score" INTEGER NOT NULL,
    "totalQ" INTEGER NOT NULL,
    "correctQ" INTEGER NOT NULL,
    "answers" TEXT NOT NULL,
    "completedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "quiz_attempts_pkey" PRIMARY KEY ("id")
);

CREATE INDEX IF NOT EXISTS "quiz_attempts_candidateId_idx" ON "quiz_attempts"("candidateId");
CREATE INDEX IF NOT EXISTS "quiz_attempts_quizId_idx" ON "quiz_attempts"("quizId");

ALTER TABLE "quiz_attempts" DROP CONSTRAINT IF EXISTS "quiz_attempts_quizId_fkey";
ALTER TABLE "quiz_attempts" ADD CONSTRAINT "quiz_attempts_quizId_fkey"
    FOREIGN KEY ("quizId") REFERENCES "quizzes"("id") ON DELETE CASCADE ON UPDATE CASCADE;

ALTER TABLE "quiz_attempts" DROP CONSTRAINT IF EXISTS "quiz_attempts_candidateId_fkey";
ALTER TABLE "quiz_attempts" ADD CONSTRAINT "quiz_attempts_candidateId_fkey"
    FOREIGN KEY ("candidateId") REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE;

-- ─── 2. Colonne requiredQuizzes sur job_offers ─────────────

ALTER TABLE job_offers ADD COLUMN IF NOT EXISTS "requiredQuizzes" TEXT NOT NULL DEFAULT '[]';

-- ─── 3. Seed des 6 quizzes ─────────────────────────────────

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'Python', 'Python — Fondamentaux & Best Practices',
  'Variables, structures de données, OOP, décorateurs, async.', 'INTERMEDIATE',
  '[{"id":"py1","text":"Quel est le résultat de `list(map(lambda x: x**2, [1,2,3]))`?","options":["[1, 4, 9]","[2, 4, 6]","[1, 2, 3]","Erreur TypeError"],"correctIndex":0,"explanation":"map applique la fonction lambda à chaque élément, produisant les carrés."},{"id":"py2","text":"Qu''est-ce qu''un décorateur en Python ?","options":["Une classe qui hérite d''une autre","Une fonction qui prend une fonction en argument et retourne une nouvelle fonction","Un commentaire de documentation","Un type d''annotation de variable"],"correctIndex":1,"explanation":"Un décorateur est un pattern de higher-order function qui enveloppe une fonction existante."},{"id":"py3","text":"Quelle est la différence entre `deepcopy` et `copy` ?","options":["Il n''y a pas de différence","`copy` copie l''objet et ses références, `deepcopy` copie récursivement tous les objets imbriqués","`deepcopy` est plus rapide","`copy` ne fonctionne pas avec les listes"],"correctIndex":1,"explanation":"copy.copy() crée une copie superficielle (shallow), copy.deepcopy() crée une copie profonde (deep) de tous les objets imbriqués."},{"id":"py4","text":"Que retourne `type([])` ?","options":["array","<class ''list''>","list","None"],"correctIndex":1,"explanation":"type() retourne le type de l''objet sous forme de classe."},{"id":"py5","text":"Comment déclarer une méthode de classe (pas d''instance) en Python ?","options":["@staticmethod + self comme premier param","@classmethod + cls comme premier param","Aucun décorateur, juste ne pas utiliser self","@property"],"correctIndex":1,"explanation":"@classmethod reçoit la classe (cls) comme premier argument au lieu de l''instance (self)."},{"id":"py6","text":"Quelle instruction permet d''itérer sur les clés ET valeurs d''un dict ?","options":["for k in d.keys()","for k, v in d.items()","for k, v in d.values()","for k, v in enumerate(d)"],"correctIndex":1,"explanation":"dict.items() retourne des tuples (clé, valeur) permettant de les déstructurer directement."},{"id":"py7","text":"Que fait le mot-clé `yield` ?","options":["Retourne une valeur et termine la fonction","Suspend la fonction et retourne une valeur, permettant de reprendre à ce point","Lève une exception","Attend la fin d''une coroutine async"],"correctIndex":1,"explanation":"yield transforme une fonction en générateur — elle peut produire plusieurs valeurs successives sans tout charger en mémoire."},{"id":"py8","text":"Quelle est la complexité temporelle de `in` sur un set Python ?","options":["O(n)","O(log n)","O(1) en moyenne","O(n²)"],"correctIndex":2,"explanation":"Les sets utilisent une table de hachage — la recherche est O(1) en moyenne."},{"id":"py9","text":"Que signifie `*args` dans une définition de fonction ?","options":["Un argument obligatoire nommé args","Tous les arguments keyword","Un nombre variable d''arguments positionnels passés comme tuple","Un pointeur vers une fonction"],"correctIndex":2,"explanation":"*args capture les arguments positionnels supplémentaires dans un tuple."},{"id":"py10","text":"Comment lire un fichier ligne par ligne de manière efficace en mémoire ?","options":["f.read().split(''\\n'')","f.readlines()","Itérer directement sur l''objet fichier avec `for line in f`","f.readline() dans une boucle while True"],"correctIndex":2,"explanation":"Itérer sur l''objet fichier est memory-efficient car Python lit une ligne à la fois sans tout charger."}]',
  12, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
  questions = EXCLUDED.questions, "timeLimit" = EXCLUDED."timeLimit", "isActive" = true, "updatedAt" = NOW();

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'JavaScript', 'JavaScript — ES6+ & Async',
  'Closures, promises, event loop, modules, types.', 'INTERMEDIATE',
  '[{"id":"js1","text":"Quelle est la différence entre `var`, `let` et `const` ?","options":["Aucune différence en pratique","`var` est function-scoped et hoisted, `let`/`const` sont block-scoped","`const` ne peut pas stocker des objets","`let` est global, `const` est local"],"correctIndex":1,"explanation":"var a une portée fonction et est hoistée. let et const ont une portée bloc. const interdit la réaffectation mais pas la mutation d''objets."},{"id":"js2","text":"Qu''est-ce qu''une closure ?","options":["Une fonction sans return","Une fonction qui ferme son scope et n''a plus accès aux variables extérieures","Une fonction interne qui capture et mémorise les variables de son scope englobant","Une classe ES6"],"correctIndex":2,"explanation":"Une closure est une fonction qui se souvient de l''environnement dans lequel elle a été créée, y compris ses variables libres."},{"id":"js3","text":"Que vaut `typeof null` ?","options":["''null''","''undefined''","''object''","''boolean''"],"correctIndex":2,"explanation":"C''est un bug historique de JavaScript — typeof null retourne ''object'' depuis la première version."},{"id":"js4","text":"Comment fonctionne l''event loop JavaScript ?","options":["JavaScript est multi-threadé et utilise plusieurs boucles","Le call stack exécute le code synchrone, les callbacks async sont mis en queue et exécutés quand le stack est vide","Les Promises bloquent le thread principal","setTimeout garantit une exécution exacte après le délai indiqué"],"correctIndex":1,"explanation":"L''event loop surveille le call stack et la callback queue — quand le stack est vide, elle pousse le prochain callback de la queue."},{"id":"js5","text":"Que retourne `Promise.all([p1, p2, p3])` ?","options":["La première promise résolue","Une promise résolue avec un tableau des résultats si toutes réussissent, rejetée dès qu''une échoue","Une promise qui attend la plus lente","Un tableau de promises non résolues"],"correctIndex":1,"explanation":"Promise.all résout quand toutes les promises réussissent, ou rejette immédiatement dès qu''une seule échoue."},{"id":"js6","text":"Quelle est la sortie de `[1,2,3].map(String)` ?","options":["[''1'',''2'',''3'']","[1,2,3]","[''String'',''String'',''String'']","Erreur"],"correctIndex":0,"explanation":"String est passé comme callback — String() sur un nombre retourne sa représentation string."},{"id":"js7","text":"Comment fonctionne le destructuring d''objet avec valeur par défaut ?","options":["const { a = 5 } = obj — a vaut 5 si obj.a est undefined","const { a: 5 } = obj","const { a ?? 5 } = obj","Ce n''est pas possible en JS natif"],"correctIndex":0,"explanation":"La syntaxe { a = defaultValue } assigne la valeur par défaut si la propriété est undefined ou absente."},{"id":"js8","text":"Qu''est-ce que le prototype chain en JavaScript ?","options":["Un design pattern de chaining de méthodes","Le mécanisme par lequel un objet hérite des propriétés de son prototype via __proto__","Une façon d''importer des modules","La chaîne d''appels de callbacks"],"correctIndex":1,"explanation":"Chaque objet a une propriété __proto__ pointant vers son prototype. JS remonte cette chaîne pour résoudre les propriétés."},{"id":"js9","text":"Que fait `Object.freeze()` ?","options":["Supprime toutes les propriétés de l''objet","Rend l''objet immutable — aucune propriété ne peut être ajoutée, modifiée ou supprimée","Convertit l''objet en JSON","Crée une copie profonde de l''objet"],"correctIndex":1,"explanation":"Object.freeze() empêche toute modification. Attention : c''est un freeze superficiel — les objets imbriqués restent mutables."},{"id":"js10","text":"Quelle méthode de tableau retourne un nouveau tableau sans modifier l''original ?","options":["splice()","sort()","push()","map()"],"correctIndex":3,"explanation":"map(), filter(), slice(), concat() retournent de nouveaux tableaux. splice(), sort(), push(), pop() modifient le tableau en place."}]',
  12, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
  questions = EXCLUDED.questions, "timeLimit" = EXCLUDED."timeLimit", "isActive" = true, "updatedAt" = NOW();

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'React', 'React — Hooks, State & Performance',
  'Composants, hooks, rendu, context, optimisation.', 'INTERMEDIATE',
  '[{"id":"rct1","text":"Quelle est la règle principale des hooks React ?","options":["Ils ne peuvent être utilisés que dans des classes","Ils doivent être appelés au top-level d''un composant fonctionnel, pas dans des conditions ou boucles","Chaque composant ne peut avoir qu''un seul hook","Ils ne peuvent pas être utilisés dans des composants enfants"],"correctIndex":1,"explanation":"Les hooks doivent toujours être appelés dans le même ordre à chaque rendu — donc pas dans des conditions, boucles ou fonctions imbriquées."},{"id":"rct2","text":"Quand `useEffect` s''exécute-t-il avec un tableau de dépendances vide `[]` ?","options":["À chaque rendu","Uniquement au premier rendu (mount)","Jamais","Uniquement au démontage (unmount)"],"correctIndex":1,"explanation":"useEffect avec [] simule componentDidMount — il s''exécute une seule fois après le premier rendu."},{"id":"rct3","text":"Quelle est la différence entre `useMemo` et `useCallback` ?","options":["Ils sont identiques","useMemo mémoïse une valeur calculée, useCallback mémoïse une fonction","useCallback mémoïse une valeur, useMemo mémoïse une fonction","useMemo est pour les classes, useCallback pour les fonctions"],"correctIndex":1,"explanation":"useMemo(() => computeValue(), deps) mémoïse le résultat d''un calcul. useCallback(() => fn, deps) mémoïse la référence de la fonction."},{"id":"rct4","text":"Pourquoi la clé (`key`) est-elle importante dans les listes React ?","options":["Elle améliore le CSS","Elle n''est pas importante, c''est juste une convention","Elle aide React à identifier quels éléments ont changé pour optimiser le re-rendu","Elle doit toujours être l''index du tableau"],"correctIndex":2,"explanation":"React utilise les clés pour associer les éléments DOM virtuels entre les renders et minimiser les mutations DOM réelles."},{"id":"rct5","text":"Qu''est-ce que le Context API résout ?","options":["La gestion des requêtes HTTP","Le prop drilling — passer des données à travers plusieurs niveaux de composants sans passer par les props","L''optimisation du rendu","La gestion des effets de bord"],"correctIndex":1,"explanation":"Context permet de partager des données globales (auth, thème) sans les passer manuellement à chaque composant intermédiaire."},{"id":"rct6","text":"Comment éviter les re-rendus inutiles d''un composant enfant ?","options":["Utiliser useState dans l''enfant","Envelopper le composant avec React.memo() et mémoïser les callbacks passés en props","Utiliser useEffect","Utiliser useRef"],"correctIndex":1,"explanation":"React.memo compare les props superficiellement. Si les callbacks sont recréés à chaque rendu parent, il faut aussi useCallback pour stabiliser leurs références."},{"id":"rct7","text":"Que fait `useRef` principalement ?","options":["Il crée un état qui déclenche un re-rendu quand il change","Il persiste une valeur mutable entre les rendus sans déclencher de re-rendu","Il référence le composant parent","Il remplace useState pour les valeurs primitives"],"correctIndex":1,"explanation":"useRef retourne un objet {current} dont la mutation ne déclenche pas de re-rendu — utile pour accéder au DOM ou stocker des valeurs persistantes."},{"id":"rct8","text":"Quelle est la forme correcte pour mettre à jour un objet dans useState ?","options":["setState(state.key = newValue)","setState({ ...state, key: newValue })","state.key = newValue; setState(state)","setState(Object.assign(state, { key: newValue }))"],"correctIndex":1,"explanation":"React requiert une nouvelle référence d''objet pour détecter le changement. Il faut spreader l''état précédent et remplacer les clés modifiées."},{"id":"rct9","text":"Qu''est-ce que le Reconciliation en React ?","options":["Le processus de résolution des conflits entre composants","L''algorithme qui compare le virtual DOM précédent et le nouveau pour minimiser les mises à jour réelles du DOM","La synchronisation des states entre composants","Le processus de compilation JSX"],"correctIndex":1,"explanation":"React Fiber compare deux arbres de virtual DOM et calcule le diff minimum à appliquer au vrai DOM."},{"id":"rct10","text":"Quand doit-on utiliser `useReducer` plutôt que `useState` ?","options":["Jamais, useState suffit toujours","Quand la logique de mise à jour est complexe avec plusieurs sous-valeurs interdépendantes ou beaucoup de transitions d''état","Uniquement pour les tableaux","Quand on veut éviter les re-rendus"],"correctIndex":1,"explanation":"useReducer est préférable pour des états complexes avec plusieurs actions (pattern similaire à Redux) ou quand l''état suivant dépend du précédent."}]',
  12, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
  questions = EXCLUDED.questions, "timeLimit" = EXCLUDED."timeLimit", "isActive" = true, "updatedAt" = NOW();

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'SQL', 'SQL — Requêtes & Optimisation',
  'Jointures, agrégations, indexes, transactions, fenêtres.', 'INTERMEDIATE',
  '[{"id":"sql1","text":"Quelle est la différence entre `INNER JOIN` et `LEFT JOIN` ?","options":["Aucune différence","INNER JOIN retourne uniquement les lignes avec correspondance dans les deux tables. LEFT JOIN retourne toutes les lignes de la table gauche, avec NULL si pas de correspondance à droite","LEFT JOIN est plus rapide","INNER JOIN inclut les doublons, LEFT JOIN non"],"correctIndex":1,"explanation":"INNER JOIN = intersection. LEFT JOIN = toutes les lignes gauche + correspondances droite (NULL si absent)."},{"id":"sql2","text":"À quoi sert la clause `HAVING` ?","options":["Filtrer les lignes avant le GROUP BY","Filtrer les groupes après agrégation, là où WHERE ne peut pas être utilisé","Trier les résultats","Limiter le nombre de résultats"],"correctIndex":1,"explanation":"WHERE filtre avant GROUP BY (sur des lignes). HAVING filtre après GROUP BY (sur des groupes), permettant d''utiliser des fonctions d''agrégation."},{"id":"sql3","text":"Qu''est-ce qu''un index et quand l''utiliser ?","options":["Un alias de table","Une structure de données accélérant les lookups sur une colonne, utile sur les colonnes fréquemment filtrées/jointures","Une vue matérialisée","Un type de contrainte d''unicité uniquement"],"correctIndex":1,"explanation":"Un index (B-tree par défaut) accélère SELECT mais ralentit INSERT/UPDATE. Créer sur les colonnes de WHERE, JOIN ON, ORDER BY fréquents."},{"id":"sql4","text":"Que fait `ROW_NUMBER() OVER (PARTITION BY dept ORDER BY salary DESC)` ?","options":["Trie les résultats par salaire","Attribue un rang unique à chaque ligne dans chaque groupe (dept), ordonné par salaire décroissant","Compte le nombre d''employés par département","Calcule le salaire moyen par département"],"correctIndex":1,"explanation":"C''est une fonction de fenêtre. PARTITION BY divise en groupes, ORDER BY détermine le rang — idéal pour ''top N par groupe''."},{"id":"sql5","text":"Quelle est la différence entre `DELETE`, `TRUNCATE` et `DROP` ?","options":["Ce sont des synonymes","DELETE supprime des lignes filtrables et est rollbackable. TRUNCATE vide la table entière rapidement. DROP supprime la table et sa structure","TRUNCATE est plus lent que DELETE","DROP garde la structure de la table"],"correctIndex":1,"explanation":"DELETE : ligne par ligne, WHERE possible, transactionnel. TRUNCATE : reset rapide, pas de WHERE. DROP : supprime table + données + structure."},{"id":"sql6","text":"Qu''est-ce qu''une CTE (Common Table Expression) ?","options":["Un type d''index","Un résultat intermédiaire nommé défini avec WITH, réutilisable dans la requête principale","Une contrainte de table","Un type de jointure"],"correctIndex":1,"explanation":"WITH cte AS (SELECT ...) SELECT * FROM cte — les CTEs rendent les requêtes complexes plus lisibles et permettent la récursivité."},{"id":"sql7","text":"Que signifie ACID pour les transactions ?","options":["Async, Concurrent, Indexed, Distributed","Atomicité, Cohérence, Isolation, Durabilité","Available, Consistent, Independent, Durable","Automated, Cached, Incremental, Dynamic"],"correctIndex":1,"explanation":"ACID garantit l''intégrité des transactions : tout ou rien (A), état valide (C), transactions isolées (I), données persistées après commit (D)."},{"id":"sql8","text":"Comment optimiser une requête avec `EXPLAIN ANALYZE` ?","options":["En ajoutant ORDER BY","En analysant le plan d''exécution pour identifier les Seq Scan coûteux et ajouter des index appropriés","En utilisant SELECT *","En supprimant les jointures"],"correctIndex":1,"explanation":"EXPLAIN ANALYZE exécute la requête et affiche le plan réel. Un Seq Scan sur une grande table indique souvent un index manquant."},{"id":"sql9","text":"Quelle est la différence entre `UNION` et `UNION ALL` ?","options":["UNION ALL est interdit en SQL standard","UNION déduplique les lignes (plus lent), UNION ALL conserve tous les doublons (plus rapide)","UNION est plus rapide que UNION ALL","Ils sont identiques"],"correctIndex":1,"explanation":"UNION effectue un DISTINCT implicite (coût supplémentaire). UNION ALL empile simplement les résultats sans déduplication."},{"id":"sql10","text":"Qu''est-ce qu''un deadlock en base de données ?","options":["Une requête qui tourne indéfiniment","Une situation où deux transactions s''attendent mutuellement sur des verrous qu''elles détiennent","Un index corrompu","Une contrainte violée"],"correctIndex":1,"explanation":"T1 verrouille A et attend B. T2 verrouille B et attend A. Cycle d''attente infini — le SGBD détecte et annule une des deux transactions."}]',
  12, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
  questions = EXCLUDED.questions, "timeLimit" = EXCLUDED."timeLimit", "isActive" = true, "updatedAt" = NOW();

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'DevOps', 'DevOps — Docker, K8s & CI/CD',
  'Conteneurs, orchestration, pipelines, infrastructure as code.', 'INTERMEDIATE',
  '[{"id":"dv1","text":"Quelle est la différence entre une image Docker et un conteneur ?","options":["Ce sont des synonymes","Une image est un template immuable. Un conteneur est une instance en cours d''exécution de cette image","Un conteneur est plus léger qu''une image","Une image s''exécute sur le réseau, un conteneur en local"],"correctIndex":1,"explanation":"Image = blueprint read-only (Dockerfile compilé). Conteneur = instance live avec une layer d''écriture propre, créée depuis l''image."},{"id":"dv2","text":"Que fait `COPY` vs `ADD` dans un Dockerfile ?","options":["Ils sont identiques","COPY copie des fichiers locaux. ADD fait la même chose mais supporte aussi les URLs et l''extraction automatique de tar","ADD est deprecated","COPY supporte les URLs, ADD non"],"correctIndex":1,"explanation":"Préférer COPY pour la transparence. ADD est utile uniquement pour extraire des archives locales."},{"id":"dv3","text":"Qu''est-ce qu''un Kubernetes Pod ?","options":["Un nœud dans le cluster","La plus petite unité déployable K8s — un ou plusieurs conteneurs partageant le réseau et le stockage","Un namespace K8s","Un load balancer"],"correctIndex":1,"explanation":"Un Pod encapsule un ou plusieurs conteneurs co-localisés qui partagent l''IP, les ports et les volumes. C''est l''unité d''orchestration de base."},{"id":"dv4","text":"Quelle est la différence entre `Deployment` et `StatefulSet` en K8s ?","options":["Ils sont identiques","Deployment pour les workloads stateless (pods interchangeables). StatefulSet pour les workloads avec état persistant (DB, queues) — identité stable et ordre de démarrage","StatefulSet est plus récent et remplace Deployment","Deployment ne supporte pas le scaling"],"correctIndex":1,"explanation":"StatefulSet garantit un nom stable (pod-0, pod-1), un stockage persistant par pod et un ordre d''opération — essentiel pour MySQL, Kafka, etc."},{"id":"dv5","text":"Que teste une health check `liveness probe` vs `readiness probe` ?","options":["Ce sont les mêmes","Liveness : le conteneur est-il vivant (sinon restart). Readiness : le conteneur est-il prêt à recevoir du trafic (sinon retiré du load balancer)","Readiness vérifie les dépendances externes, liveness vérifie le code","Liveness est pour la prod, readiness pour le staging"],"correctIndex":1,"explanation":"Liveness échoue → K8s redémarre le conteneur. Readiness échoue → K8s retire le pod du Service endpoint mais ne le redémarre pas."},{"id":"dv6","text":"Qu''est-ce que l''infrastructure as code (IaC) ?","options":["Écrire des scripts bash pour déployer","Définir et provisionner l''infrastructure via des fichiers de configuration versionnés (Terraform, Pulumi, CloudFormation)","Documenter l''infrastructure dans un wiki","Utiliser une interface graphique cloud"],"correctIndex":1,"explanation":"IaC permet de versionner, tester et reproduire l''infrastructure. Le state est géré par l''outil (terraform.tfstate)."},{"id":"dv7","text":"Dans un pipeline CI/CD, que signifie ''shift left'' ?","options":["Déplacer les tests en production","Détecter les problèmes le plus tôt possible dans le cycle de développement (lint, tests unitaires avant les tests d''intégration)","Déployer de droite à gauche","Réduire le nombre de branches Git"],"correctIndex":1,"explanation":"Shift left = déplacer les contrôles qualité vers la gauche du pipeline. Plus un bug est détecté tôt, moins il coûte cher à corriger."},{"id":"dv8","text":"Quelle est la différence entre déploiement Blue/Green et Canary ?","options":["Ce sont des termes identiques","Blue/Green bascule 100% du trafic vers la nouvelle version. Canary envoie progressivement un % croissant du trafic vers la nouvelle version","Canary est plus risqué que Blue/Green","Blue/Green ne permet pas de rollback"],"correctIndex":1,"explanation":"Blue/Green = deux environnements, bascule instantanée. Canary = rollout graduel permettant de tester sur un sous-ensemble d''utilisateurs réels."},{"id":"dv9","text":"À quoi sert un ConfigMap dans Kubernetes ?","options":["Stocker des secrets de manière sécurisée","Stocker des données de configuration non-sensibles (env vars, fichiers de config) découplées des images conteneur","Configurer le réseau du cluster","Définir les ressources CPU/RAM des pods"],"correctIndex":1,"explanation":"ConfigMap découple la config de l''image. Pour les données sensibles, utiliser Secret."},{"id":"dv10","text":"Qu''est-ce que le ''GitOps'' ?","options":["Utiliser Git pour le versioning du code uniquement","Utiliser Git comme source de vérité pour l''infrastructure et les déploiements — tout changement passe par une PR, un opérateur (ArgoCD, Flux) synchronise l''état réel","Une alternative à GitHub","Un workflow Git avec des branches obligatoires"],"correctIndex":1,"explanation":"En GitOps, le repo Git est la source de vérité. ArgoCD ou Flux observent le repo et reconcilent l''état K8s avec ce qui est déclaré dans Git."}]',
  12, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
  questions = EXCLUDED.questions, "timeLimit" = EXCLUDED."timeLimit", "isActive" = true, "updatedAt" = NOW();

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'Data Science', 'Data Science — ML & Statistiques',
  'Modèles, évaluation, features, biais, statistiques.', 'INTERMEDIATE',
  '[{"id":"ds1","text":"Qu''est-ce que l''overfitting et comment le détecter ?","options":["Le modèle est trop simple et a une erreur élevée sur les données d''entraînement","Le modèle performe très bien en training mais mal en validation/test — gap important entre les deux scores","Le modèle prend trop de temps à s''entraîner","Le dataset est trop grand"],"correctIndex":1,"explanation":"L''overfitting = le modèle mémorise le training set au lieu d''apprendre des patterns généralisables. Un gap train/val élevé est le signe principal."},{"id":"ds2","text":"Quelle métrique utiliser pour un problème de classification déséquilibré (99% classe A, 1% classe B) ?","options":["Accuracy","F1-score ou AUC-ROC, car l''accuracy est trompeuse (un modèle qui prédit toujours A aurait 99%)","MSE","R²"],"correctIndex":1,"explanation":"Sur des datasets déséquilibrés, l''accuracy est inutile. F1-score balance précision/rappel. AUC-ROC mesure la capacité discriminante indépendamment du seuil."},{"id":"ds3","text":"Qu''est-ce que la validation croisée (cross-validation) ?","options":["Tester le modèle sur un seul jeu de test","Diviser les données en K folds, entraîner K fois sur K-1 folds et évaluer sur le fold restant, puis moyenner les scores","Entraîner plusieurs modèles différents","Dupliquer les données pour augmenter le dataset"],"correctIndex":1,"explanation":"K-fold CV donne une estimation plus robuste de la performance généralisation en utilisant toutes les données à la fois pour le train et le test."},{"id":"ds4","text":"Quelle est la différence entre régression L1 (Lasso) et L2 (Ridge) ?","options":["Aucune différence pratique","L1 (Lasso) produit des solutions sparses (certains coefficients à 0, sélection de features). L2 (Ridge) réduit tous les coefficients sans les annuler","L2 est utilisé pour la classification, L1 pour la régression","L1 est plus rapide à calculer"],"correctIndex":1,"explanation":"Lasso (L1) pénalise la somme des valeurs absolues → sparsité. Ridge (L2) pénalise la somme des carrés → shrinkage uniforme."},{"id":"ds5","text":"Qu''est-ce que le biais (bias) vs la variance dans le trade-off ?","options":["Biais = erreur aléatoire, Variance = erreur systématique","Biais = erreur systématique due à des hypothèses de modèle trop simplistes. Variance = sensibilité aux fluctuations du training set","Ce sont des synonymes","Biais mesure l''équité du modèle, variance mesure la rapidité"],"correctIndex":1,"explanation":"High bias = underfitting (modèle trop simple). High variance = overfitting (trop sensible aux données d''entraînement)."},{"id":"ds6","text":"Pourquoi normaliser/standardiser les features ?","options":["Pour accélérer le chargement des données","Pour que les features à grande échelle ne dominent pas l''optimisation — essentiel pour les algorithmes basés sur les distances (KNN, SVM, gradient descent)","Pour rendre les données plus lisibles","Ce n''est jamais nécessaire"],"correctIndex":1,"explanation":"Sans normalisation, une feature en milliers (revenus) domine une feature en 0-1 (score). Les arbres de décision sont insensibles à l''échelle, pas les modèles linéaires."},{"id":"ds7","text":"Qu''est-ce que le data leakage ?","options":["Des données qui fuient hors du serveur","L''introduction involontaire d''informations du future ou du test set dans le training — produit des métriques artificiellement bonnes non reproductibles en prod","Des valeurs manquantes dans le dataset","Un dataset trop grand pour la mémoire"],"correctIndex":1,"explanation":"Ex : normaliser avant de splitter (les stats du test contaminent le train). Le leakage cause des modèles qui semblent parfaits mais échouent en prod."},{"id":"ds8","text":"Quelle est la complexité de l''algorithme KNN pour la prédiction ?","options":["O(1)","O(log n)","O(n × d) où n est la taille du dataset et d le nombre de dimensions","O(n²)"],"correctIndex":2,"explanation":"KNN calcule la distance entre le point à prédire et tous les points d''entraînement — O(n×d). Optimisations possibles avec des KD-trees ou Ball trees."},{"id":"ds9","text":"Que mesure le coefficient R² (R-squared) ?","options":["L''erreur absolue moyenne","La proportion de variance de la variable cible expliquée par le modèle (1 = parfait, 0 = pas mieux que la moyenne, <0 = pire que la moyenne)","La corrélation entre deux variables","La précision de classification"],"correctIndex":1,"explanation":"R² = 1 - SS_res/SS_tot. Un R² de 0.85 signifie que le modèle explique 85% de la variance."},{"id":"ds10","text":"Comment gérer les valeurs manquantes dans un dataset ?","options":["Toujours les supprimer","Selon le contexte : supprimer si peu nombreuses et MCAR, imputer par médiane/mode/KNN/modèle si MAR, ou encoder la missingness comme feature si informative","Les remplacer par 0","Ignorer — les algorithmes ML gèrent automatiquement"],"correctIndex":1,"explanation":"MCAR/MAR/MNAR détermine la stratégie. L''imputation par médiane/mode est simple mais l''imputation multiple (MICE) est plus robuste."}]',
  12, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
  questions = EXCLUDED.questions, "timeLimit" = EXCLUDED."timeLimit", "isActive" = true, "updatedAt" = NOW();

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'Spark', 'Apache Spark — Big Data & Traitement distribué',
  'RDD, DataFrames, transformations, optimisation, Spark SQL.', 'ADVANCED',
  '[{"id":"sp1","text":"Quelle est la différence entre une transformation et une action en Spark ?","options":["Aucune différence","Une transformation est lazy (crée un nouveau RDD sans exécuter), une action déclenche l''exécution réelle","Une action est lazy, une transformation est immédiate","Les transformations modifient le RDD en place"],"correctIndex":1,"explanation":"Spark utilise l''évaluation paresseuse — les transformations (map, filter) construisent un DAG. L''action (collect, count, save) déclenche l''exécution réelle."},{"id":"sp2","text":"Qu''est-ce qu''un RDD (Resilient Distributed Dataset) ?","options":["Une base de données distribuée","Une collection immuable et distribuée d''objets pouvant être traitée en parallèle, avec tolérance aux pannes via le lignage","Un format de fichier Spark","Un type de jointure Spark"],"correctIndex":1,"explanation":"RDD = collection immuable, partitionnée et distribuée. La tolérance aux pannes vient du lignage (DAG des transformations) permettant de recalculer les partitions perdues."},{"id":"sp3","text":"Pourquoi préférer les DataFrames/Datasets aux RDDs ?","options":["Les RDDs sont plus récents","Les DataFrames utilisent le Catalyst optimizer et Tungsten pour des optimisations automatiques de plan d''exécution — bien plus rapides en pratique","Les DataFrames sont plus simples à déboguer","Aucune raison, c''est identique"],"correctIndex":1,"explanation":"Catalyst analyse et optimise les requêtes (push-down predicates, reorder joins). Tungsten optimise la mémoire et le CPU. Les RDDs nécessitent une optimisation manuelle."},{"id":"sp4","text":"Qu''est-ce que le ''shuffling'' en Spark et pourquoi est-il coûteux ?","options":["C''est le partitionnement initial des données","C''est le transfert de données entre partitions/exécuteurs lors d''opérations comme groupBy ou join — implique I/O disque et réseau","C''est la sérialisation des objets Java","C''est le chargement initial des données"],"correctIndex":1,"explanation":"Le shuffle nécessite d''écrire sur disque, transférer sur le réseau, et relire. Minimiser avec broadcast joins, pre-partitioning, ou éviter groupByKey au profit de reduceByKey."},{"id":"sp5","text":"Quelle est la différence entre `cache()` et `persist()` ?","options":["Ils sont identiques","cache() = persist(MEMORY_ONLY). persist() permet de choisir le niveau de stockage (mémoire, disque, sérialisé, répliqué)","persist() est deprecated","cache() utilise le disque, persist() la mémoire"],"correctIndex":1,"explanation":"cache() est un raccourci pour persist(StorageLevel.MEMORY_ONLY). persist() offre des niveaux comme MEMORY_AND_DISK, MEMORY_ONLY_SER, DISK_ONLY, etc."},{"id":"sp6","text":"Qu''est-ce que le Catalyst Optimizer ?","options":["Un outil de monitoring Spark","Le moteur d''optimisation de requêtes de Spark SQL qui transforme un plan logique en plan physique optimisé","Un gestionnaire de mémoire","Un format de sérialisation"],"correctIndex":1,"explanation":"Catalyst parse la requête → plan logique → plan logique optimisé → plan physique → code généré (Whole-Stage CodeGen)."},{"id":"sp7","text":"Comment éviter les problèmes de data skew (déséquilibre de partitions) ?","options":["Augmenter la mémoire des exécuteurs","Techniques : salting (ajouter un préfixe aléatoire à la clé), broadcast join pour les petites tables, repartitionner avant le join","Diminuer le nombre de partitions","Utiliser des RDDs au lieu de DataFrames"],"correctIndex":1,"explanation":"Le data skew concentre tout le travail sur quelques partitions. Le salting distribue artificiellement les clés fréquentes. Le broadcast join évite le shuffle pour les petites tables."},{"id":"sp8","text":"Qu''est-ce que Spark Streaming / Structured Streaming ?","options":["Un format de fichier streaming","Un moteur de traitement de flux en micro-batches (ou continu) permettant de traiter des données en temps réel avec les APIs DataFrame","Une base de données temps réel","Un outil de monitoring"],"correctIndex":1,"explanation":"Structured Streaming traite les flux comme une table infinie. Le moteur gère automatiquement l''état, les checkpoints et la tolérance aux pannes (exactly-once avec Kafka)."},{"id":"sp9","text":"Quelle est la différence entre `repartition()` et `coalesce()` ?","options":["Ils sont identiques","repartition() peut augmenter ou réduire (full shuffle). coalesce() réduit uniquement en évitant le shuffle complet — plus efficace pour réduire","coalesce() augmente le nombre de partitions","repartition() ne fait pas de shuffle"],"correctIndex":1,"explanation":"repartition(n) fait un full shuffle — utile pour rééquilibrer. coalesce(n) fusionne des partitions localement sans shuffle — idéal avant d''écrire un fichier pour réduire le nombre de sorties."},{"id":"sp10","text":"Qu''est-ce qu''un broadcast join et quand l''utiliser ?","options":["Un join qui diffuse le résultat à tous les workers","Une technique qui copie la petite table dans la mémoire de chaque exécuteur pour éviter le shuffle — idéal quand une table est < quelques centaines de MB","Un join asynchrone","Un join uniquement pour les DataFrames"],"correctIndex":1,"explanation":"broadcast() envoie la petite table à chaque exécuteur — élimine le shuffle coûteux. Spark peut le décider automatiquement si spark.sql.autoBroadcastJoinThreshold est respecté (défaut 10MB)."}]',
  15, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
  questions = EXCLUDED.questions, "timeLimit" = EXCLUDED."timeLimit", "isActive" = true, "updatedAt" = NOW();

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'Databricks', 'Databricks — Lakehouse & Delta Lake',
  'Delta Lake, Unity Catalog, notebooks, clusters, MLflow.', 'ADVANCED',
  '[{"id":"db1","text":"Qu''est-ce que le Lakehouse Architecture ?","options":["Une architecture Data Warehouse classique","Une architecture combinant la flexibilité et le faible coût du Data Lake avec la fiabilité et les performances du Data Warehouse (ACID, schema enforcement)","Un type de cluster Databricks","Un format de fichier"],"correctIndex":1,"explanation":"Le Lakehouse (Delta Lake) stocke les données brutes sur objet storage (S3/ADLS) tout en offrant les garanties ACID, le time travel, et les performances SQL du Data Warehouse."},{"id":"db2","text":"Quelles garanties ACID offre Delta Lake ?","options":["Seulement Atomicité et Durabilité","Atomicité, Cohérence, Isolation, Durabilité — via un transaction log (delta log) JSON stocké avec les données Parquet","Delta Lake n''offre pas de garanties ACID","Seulement sur les lectures"],"correctIndex":1,"explanation":"Delta Lake maintient un _delta_log contenant toutes les transactions. Chaque commit est atomique. Les lectures sont toujours cohérentes même pendant une écriture."},{"id":"db3","text":"Qu''est-ce que le Time Travel dans Delta Lake ?","options":["Un outil de scheduling","La capacité de requêter des versions précédentes d''une table via VERSION AS OF ou TIMESTAMP AS OF","Un mécanisme de backup","Un type de join temporel"],"correctIndex":1,"explanation":"Delta Lake conserve l''historique des versions. SELECT * FROM table VERSION AS OF 5 ou TIMESTAMP AS OF ''2024-01-01'' permet d''auditer ou de restaurer des données."},{"id":"db4","text":"Qu''est-ce que Unity Catalog dans Databricks ?","options":["Un outil de déploiement de clusters","Une couche de gouvernance unifiée des données (métadonnées, permissions, lineage, auditing) sur tous les workspaces Databricks","Un format de stockage","Un orchestrateur de jobs"],"correctIndex":1,"explanation":"Unity Catalog centralise : catalogue de données (3 niveaux : catalog.schema.table), contrôle d''accès fin, lineage automatique des données et colonnes, et auditing."},{"id":"db5","text":"Quelle est la différence entre un cluster All-Purpose et un Job Cluster ?","options":["Ils sont identiques","All-Purpose = cluster interactif persistant pour les notebooks (plus cher). Job Cluster = cluster créé/détruit automatiquement pour un job spécifique (optimisé coût)","Job Cluster est plus puissant","All-Purpose ne supporte pas Spark"],"correctIndex":1,"explanation":"All-Purpose clusters sont facturés même en idle. Job clusters s''arrêtent automatiquement après le job — recommandé pour la production pour minimiser les coûts."},{"id":"db6","text":"Qu''est-ce que OPTIMIZE et ZORDER dans Delta Lake ?","options":["Des commandes SQL standard","OPTIMIZE compacte les petits fichiers Parquet en plus gros fichiers. ZORDER BY co-localise les données par colonnes pour accélérer les filtres sur ces colonnes","Des opérations de backup","Des types de jointures"],"correctIndex":1,"explanation":"Les écritures Delta créent beaucoup de petits fichiers (small file problem). OPTIMIZE les compacte. ZORDER est un index multi-dimensionnel qui réduit les données lues lors du filtrage."},{"id":"db7","text":"Qu''est-ce que MLflow dans le contexte Databricks ?","options":["Un outil de streaming","Une plateforme open-source de MLOps : tracking d''expériences, packaging de modèles, registry de modèles, et déploiement","Un format de données ML","Un type de cluster GPU"],"correctIndex":1,"explanation":"MLflow couvre : Tracking (métriques, params, artifacts), Projects (reproductibilité), Models (formats), Registry (versioning, staging, production). Intégré nativement dans Databricks."},{"id":"db8","text":"Qu''est-ce que le Delta Live Tables (DLT) ?","options":["Un type de table Delta classique","Un framework déclaratif pour construire des pipelines de données fiables — définir les transformations, DLT gère l''orchestration, la qualité et la tolérance aux pannes","Un outil de visualisation","Un type de cluster"],"correctIndex":1,"explanation":"DLT permet de déclarer des tables avec @dlt.table et des contraintes de qualité avec @dlt.expect. Le framework gère automatiquement les dépendances, les retries et les métriques de qualité."},{"id":"db9","text":"Comment fonctionne le Auto Loader de Databricks ?","options":["Il charge automatiquement les modules Python","Il ingère de manière incrémentale et scalable de nouveaux fichiers depuis un storage (S3, ADLS, GCS) en utilisant des notifications d''événements ou le mode directory listing","Il déploie automatiquement les clusters","Il optimise automatiquement les requêtes SQL"],"correctIndex":1,"explanation":"Auto Loader (cloudFiles) détecte les nouveaux fichiers via notifications (SQS, Event Grid) ou listing. Il maintient l''état des fichiers traités pour garantir exactement-une-fois le processing."},{"id":"db10","text":"Qu''est-ce que Photon dans Databricks ?","options":["Un outil de monitoring","Un moteur d''exécution vectorisé natif C++ remplaçant le JVM Spark pour les workloads SQL/ETL — jusqu''à 8x plus rapide sur certaines requêtes","Un format de fichier","Un type de notebook"],"correctIndex":1,"explanation":"Photon est un runtime natif C++ compatible avec les APIs Spark. Il utilise les instructions SIMD pour le traitement vectorisé. Transparent pour l''utilisateur — même APIs, meilleures performances."}]',
  15, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
  questions = EXCLUDED.questions, "timeLimit" = EXCLUDED."timeLimit", "isActive" = true, "updatedAt" = NOW();

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'AWS', 'AWS — Services Cloud & Architecture',
  'EC2, S3, Lambda, IAM, RDS, architecture cloud.', 'INTERMEDIATE',
  '[{"id":"aws1","text":"Quelle est la différence entre S3 Standard, S3-IA et S3 Glacier ?","options":["Ils sont identiques","Standard : accès fréquent. S3-IA (Infrequent Access) : moins cher mais frais d''accès. Glacier : archivage long terme très peu coûteux avec délais de récupération de minutes à heures","Glacier est plus rapide que Standard","S3-IA ne supporte pas le chiffrement"],"correctIndex":1,"explanation":"Le choix dépend de la fréquence d''accès et du budget. S3 Intelligent-Tiering déplace automatiquement les objets entre les classes selon l''utilisation."},{"id":"aws2","text":"Qu''est-ce que IAM et quels sont ses composants principaux ?","options":["Un service de base de données","Identity and Access Management : Users, Groups, Roles, Policies. Gère qui peut faire quoi sur quelles ressources AWS","Un service de monitoring","Un service réseau"],"correctIndex":1,"explanation":"IAM : Users (personnes), Groups (ensembles d''users), Roles (assumés par services/comptes), Policies (documents JSON définissant les permissions). Principe du least privilege."},{"id":"aws3","text":"Quelle est la différence entre une instance EC2 On-Demand, Reserved et Spot ?","options":["Aucune différence technique","On-Demand : paiement à l''heure sans engagement. Reserved : engagement 1-3 ans, jusqu''à 72% moins cher. Spot : capacité inutilisée AWS, jusqu''à 90% moins cher mais interruptible","Spot est plus fiable que On-Demand","Reserved ne peut pas être arrêtée"],"correctIndex":1,"explanation":"Spot instances peuvent être interrompues avec 2 minutes de préavis — idéal pour les workloads fault-tolerant (batch, ML training). Reserved pour les charges prévisibles (prod)."},{"id":"aws4","text":"Qu''est-ce qu''AWS Lambda et son modèle d''exécution ?","options":["Un service de containers","Serverless compute : code exécuté en réponse à des événements, facturation à la milliseconde, scaling automatique, pas de serveur à gérer","Un service de base de données","Un CDN"],"correctIndex":1,"explanation":"Lambda s''exécute dans des microVMs (Firecracker). Cold start = initialisation du container (~100ms-1s). Warm start = réutilisation du container existant. Timeout max 15 minutes."},{"id":"aws5","text":"Quelle est la différence entre RDS, Aurora et DynamoDB ?","options":["Ce sont des synonymes","RDS : managed SQL classique (MySQL, PostgreSQL). Aurora : SQL compatible MySQL/PostgreSQL mais re-architecturé pour le cloud (5x plus rapide). DynamoDB : NoSQL clé-valeur/document fully managed","DynamoDB est plus lent que RDS","Aurora ne supporte pas les transactions"],"correctIndex":1,"explanation":"Aurora sépare le stockage du compute et réplique sur 6 AZs automatiquement. DynamoDB offre une latence < 1ms à n''importe quelle échelle avec un modèle serverless."},{"id":"aws6","text":"Qu''est-ce qu''un VPC et pourquoi est-il important ?","options":["Un service de stockage","Virtual Private Cloud : réseau virtuel isolé dans AWS. Contrôle total sur l''adressage IP, les sous-réseaux, les tables de routage et les gateways","Un type d''instance EC2","Un service de DNS"],"correctIndex":1,"explanation":"VPC permet d''isoler les ressources AWS dans un réseau privé. Subnets publics (accès internet via IGW) et privés (pas d''accès direct). Security Groups = firewall stateful par instance."},{"id":"aws7","text":"Qu''est-ce que CloudFormation et en quoi diffère-t-il de Terraform ?","options":["Ils sont identiques","CloudFormation est l''IaC natif AWS (JSON/YAML), gratuit, intégré nativement. Terraform est multi-cloud (HashiCorp), HCL, plus flexible mais nécessite la gestion du state","Terraform est exclusivement AWS","CloudFormation supporte Azure et GCP"],"correctIndex":1,"explanation":"CloudFormation : stacks, drift detection, rollback automatique, gratuit. Terraform : provider ecosystem immense, state file (local ou remote), plan/apply workflow, portable multi-cloud."},{"id":"aws8","text":"Qu''est-ce que SQS vs SNS ?","options":["Ce sont des synonymes","SQS (Simple Queue Service) : queue de messages point-à-point, polling. SNS (Simple Notification Service) : pub/sub, un message envoyé à plusieurs subscribers (email, Lambda, SQS, HTTP)","SNS est une queue, SQS est pub/sub","SQS ne peut pas déclencher Lambda"],"correctIndex":1,"explanation":"Pattern courant : SNS fanout → multiple SQS queues pour découpler les consumers. SQS standard = au moins une livraison. SQS FIFO = exactement une livraison, ordre garanti."},{"id":"aws9","text":"Qu''est-ce que CloudWatch et quels problèmes résout-il ?","options":["Un service de déploiement","Le service de monitoring AWS : métriques, logs, alarmes, dashboards, Events (EventBridge). Permet de monitorer les ressources AWS et les applications","Un service de sauvegarde","Un CDN"],"correctIndex":1,"explanation":"CloudWatch Metrics : collecte auto les métriques AWS. Logs : centralise les logs. Alarms : déclenche des actions (SNS, Auto Scaling). Container Insights pour ECS/EKS. X-Ray pour le tracing."},{"id":"aws10","text":"Qu''est-ce que l''Auto Scaling Group (ASG) ?","options":["Un groupe d''administrateurs AWS","Un service qui ajuste automatiquement le nombre d''instances EC2 selon la demande (métriques CloudWatch, schedules) entre un min et max définis","Un type de load balancer","Un service de backup"],"correctIndex":1,"explanation":"ASG maintient un nombre souhaité d''instances, remplace automatiquement les instances défaillantes, et scale out/in selon les politiques. Couplé avec ALB pour distribuer le trafic."}]',
  12, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
  questions = EXCLUDED.questions, "timeLimit" = EXCLUDED."timeLimit", "isActive" = true, "updatedAt" = NOW();

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'Azure', 'Azure — Services Cloud Microsoft',
  'Compute, storage, networking, data, identity, DevOps.', 'INTERMEDIATE',
  '[{"id":"az1","text":"Quelle est la différence entre Azure Blob Storage, Azure Files et Azure Disks ?","options":["Ce sont des synonymes","Blob : stockage objet pour données non structurées. Files : partages NFS/SMB montables. Disks : disques persistants attachés aux VMs (SSD Premium, HDD Standard)","Azure Files remplace Azure Blobs","Azure Disks peuvent être partagés entre VMs sans configuration"],"correctIndex":1,"explanation":"Blob Storage = S3 AWS. Azure Files = NFS/SMB pour applications legacy. Managed Disks = EBS AWS, attachés à une seule VM (sauf shared disks)."},{"id":"az2","text":"Qu''est-ce qu''Azure Active Directory (Azure AD / Entra ID) ?","options":["Active Directory classique dans le cloud","Le service d''identité cloud de Microsoft — SSO, MFA, RBAC, gestion des identités pour apps cloud et hybride. Différent du Windows AD traditionnel","Un service de DNS","Un firewall"],"correctIndex":1,"explanation":"Azure AD (maintenant Entra ID) est un IDaaS cloud-native. Supporte OAuth 2.0, OIDC, SAML. Azure AD Connect synchronise avec l''AD on-prem. Conditional Access pour la sécurité Zero Trust."},{"id":"az3","text":"Quelle est la différence entre Azure Functions et Azure App Service ?","options":["Ils sont identiques","Functions : serverless event-driven, facturation à l''exécution, cold start possible. App Service : PaaS pour héberger des apps web/API avec un plan dédié, toujours disponible","App Service est serverless","Functions ne supporte pas les triggers HTTP"],"correctIndex":1,"explanation":"Functions Consumption Plan = serverless pur. Functions Premium Plan = pas de cold start. App Service = VM managée pour web apps, APIs, containers — plus prévisible mais moins élastique."},{"id":"az4","text":"Qu''est-ce qu''Azure Kubernetes Service (AKS) ?","options":["Un service de containers sans Kubernetes","Kubernetes managé sur Azure — le control plane est géré par Azure (gratuit), vous gérez les node pools. Intégré avec Azure AD, ACR, Monitor, et les réseaux Azure","Un service équivalent à Docker Compose","Un registre de containers"],"correctIndex":1,"explanation":"AKS gère les upgrades du control plane, la HA, les patches. Vous gérez les node pools (taille, count, autoscaler). Intégration native avec AGIC (Application Gateway Ingress Controller)."},{"id":"az5","text":"Qu''est-ce qu''Azure DevOps et quels sont ses composants ?","options":["Un IDE Microsoft","Suite de services DevOps : Boards (Kanban/Scrum), Repos (Git), Pipelines (CI/CD), Test Plans, Artifacts (registre de packages)","Un service de monitoring uniquement","Un équivalent d''Azure Functions"],"correctIndex":1,"explanation":"Azure Pipelines supporte YAML et GUI, multi-cloud, avec des agents hébergés ou self-hosted. Artifacts = registre npm/NuGet/Maven privé. Alternative : GitHub Actions (racheté par Microsoft)."},{"id":"az6","text":"Quelle est la différence entre Azure SQL Database et Azure Cosmos DB ?","options":["Ce sont des synonymes","Azure SQL Database : SQL Server managé, relationnel, ACID. Cosmos DB : NoSQL multi-modèle (document, graph, key-value, table), distribution globale, latence < 10ms garanti par SLA","Cosmos DB est plus lent","Azure SQL ne supporte pas les transactions"],"correctIndex":1,"explanation":"Cosmos DB offre 5 niveaux de cohérence (Strong → Eventual), multi-region writes, et plusieurs APIs (SQL, MongoDB, Cassandra, Gremlin, Table). Facturation à la RU (Request Unit)."},{"id":"az7","text":"Qu''est-ce que Azure Data Factory (ADF) ?","options":["Une base de données","Service ETL/ELT cloud — orchestration de pipelines de données entre sources hétérogènes (100+ connecteurs), transformations via Data Flows ou Spark (Databricks)","Un service de streaming","Un outil de visualisation"],"correctIndex":1,"explanation":"ADF = équivalent Azure de AWS Glue/Step Functions. Pipelines visuels, triggers (schedule, event, tumbling window), integration runtime pour sources on-prem ou cloud."},{"id":"az8","text":"Qu''est-ce qu''Azure Event Hubs vs Azure Service Bus ?","options":["Ce sont des synonymes","Event Hubs : ingestion massive d''événements (millions/s), streaming, compatible Kafka. Service Bus : messagerie enterprise fiable, queues et topics, sessions, dead-letter, transactions","Service Bus est conçu pour le streaming","Event Hubs supporte les transactions ACID"],"correctIndex":1,"explanation":"Event Hubs = Kafka managé, idéal pour la télémétrie et le streaming. Service Bus = RabbitMQ managé, idéal pour le découplage de microservices avec garanties de livraison."},{"id":"az9","text":"Qu''est-ce que Azure Monitor et Application Insights ?","options":["Des services de déploiement","Azure Monitor : plateforme de monitoring unifiée (métriques, logs, alertes). Application Insights : APM pour tracer les requêtes, dépendances, exceptions des apps","Des services de stockage","Des services réseau"],"correctIndex":1,"explanation":"Application Insights s''intègre avec les apps via SDK ou auto-instrumentation. Fournit : request rates, failure rates, dependency tracking, distributed tracing, Live Metrics Stream."},{"id":"az10","text":"Qu''est-ce qu''un Azure Resource Group et pourquoi l''utiliser ?","options":["Un groupe d''utilisateurs Azure","Un conteneur logique regroupant des ressources Azure liées — permet une gestion unifiée (déploiement, monitoring, facturation, suppression, RBAC) par projet ou environnement","Un type de VNet","Un plan App Service"],"correctIndex":1,"explanation":"Resource Group = unité d''organisation et de cycle de vie. Supprimer un RG supprime toutes ses ressources. RBAC appliqué au RG hérite à toutes les ressources."}]',
  12, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
  questions = EXCLUDED.questions, "timeLimit" = EXCLUDED."timeLimit", "isActive" = true, "updatedAt" = NOW();

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'TypeScript', 'TypeScript — Typage avancé & Bonnes pratiques',
  'Types, interfaces, génériques, utilitaires, configuration.', 'INTERMEDIATE',
  '[{"id":"ts1","text":"Quelle est la différence entre `interface` et `type` en TypeScript ?","options":["Ils sont identiques","Les deux définissent des types. interface est extensible (declaration merging, extends). type est plus flexible (unions, intersections, types conditionnels, mapped types)","type ne peut pas décrire des objets","interface supporte les unions"],"correctIndex":1,"explanation":"Préférer interface pour les objets/classes (extensible par merging). Préférer type pour les unions, intersections, aliases complexes."},{"id":"ts2","text":"Qu''est-ce qu''un type générique et pourquoi l''utiliser ?","options":["Un type qui accepte n''importe quelle valeur","Un type paramétré par un ou plusieurs types — permet d''écrire du code réutilisable et type-safe sans sacrifier la flexibilité (ex: Array<T>, Promise<T>)","Un type optionnel","Un type nullable"],"correctIndex":1,"explanation":"function identity<T>(x: T): T — T est inféré à l''appel. Les génériques évitent l''utilisation de `any` tout en gardant la réutilisabilité. Avec contraintes : <T extends object>."},{"id":"ts3","text":"Que font les types utilitaires `Partial<T>`, `Required<T>` et `Pick<T, K>` ?","options":["Ce sont des fonctions JavaScript","Partial<T> rend toutes les propriétés optionnelles. Required<T> les rend toutes obligatoires. Pick<T, K> sélectionne un sous-ensemble de propriétés K de T","Ils modifient les valeurs à runtime","Ils ne fonctionnent qu''avec les interfaces"],"correctIndex":1,"explanation":"TypeScript built-in utility types : Partial, Required, Readonly, Pick, Omit, Record<K,V>, Exclude<T,U>, Extract<T,U>, NonNullable<T>, ReturnType<F>, Parameters<F>..."},{"id":"ts4","text":"Qu''est-ce que l''opérateur `keyof` ?","options":["Une méthode JavaScript","Un opérateur TypeScript qui produit un union type de toutes les clés d''un type objet — ex: keyof { a: string; b: number } = ''a'' | ''b''","Un opérateur d''accès aux propriétés","Un type conditionnel"],"correctIndex":1,"explanation":"keyof est essentiel pour les types génériques contraints : function get<T, K extends keyof T>(obj: T, key: K): T[K] — garantit que key existe sur T et que le retour est correct."},{"id":"ts5","text":"Qu''est-ce qu''un discriminated union (union discriminée) ?","options":["Une union de types primitifs","Un pattern où chaque type de l''union a une propriété littérale commune (discriminant) permettant à TypeScript de narrower le type dans un switch/if","Un type qui exclut null","Une intersection de types"],"correctIndex":1,"explanation":"Ex: type Shape = { kind: ''circle''; radius: number } | { kind: ''square''; side: number }. Dans switch(shape.kind), TS sait exactement quel type est présent."},{"id":"ts6","text":"Que signifie `strict: true` dans tsconfig.json ?","options":["Que TypeScript génère du code strict ES6","Active un ensemble de vérifications strictes : strictNullChecks, strictFunctionTypes, strictPropertyInitialization, noImplicitAny, noImplicitThis, etc.","Que les erreurs bloquent le build","Que les imports sont stricts"],"correctIndex":1,"explanation":"strict: true est la combinaison de plusieurs flags. strictNullChecks est le plus impactant — null et undefined ne sont plus assignables à d''autres types sans vérification explicite."},{"id":"ts7","text":"Qu''est-ce qu''un type conditionnel en TypeScript ?","options":["Un type qui dépend d''une condition runtime","T extends U ? X : Y — un type qui se résout en X si T est assignable à U, sinon Y. Permet des types très expressifs comme NonNullable<T>","Un type nullable","Un type avec une valeur par défaut"],"correctIndex":1,"explanation":"Les types conditionnels permettent des transformations de types : type Flatten<T> = T extends Array<infer U> ? U : T. infer introduit une variable de type dans la condition."},{"id":"ts8","text":"Quelle est la différence entre `unknown` et `any` ?","options":["Ils sont identiques","any désactive le type checking (dangereux). unknown est type-safe — on doit vérifier/narrower le type avant de l''utiliser. Préférer unknown pour les valeurs de type inconnu","unknown est plus permissif que any","any génère des erreurs TypeScript"],"correctIndex":1,"explanation":"const x: unknown = fetchData(); x.toString() // ERREUR avec unknown. Avec any, pas d''erreur. unknown force à écrire : if (typeof x === ''string'') x.toString() — plus sûr."},{"id":"ts9","text":"Qu''est-ce que le `as const` assertion ?","options":["Un cast forcé vers un type","Infère le type le plus précis possible (types littéraux, readonly) — ex: const colors = [''red'', ''blue''] as const → readonly [''red'', ''blue''] au lieu de string[]","Rend une variable immutable à runtime","Force la compilation en mode strict"],"correctIndex":1,"explanation":"as const transforme les inférences : string → ''red'', number → 42, les tableaux deviennent readonly tuples. Très utile pour les unions littérales : type Color = typeof colors[number]."},{"id":"ts10","text":"Qu''est-ce qu''un Mapped Type en TypeScript ?","options":["Un type Array avec une fonction map","Un type créé en itérant sur les clés d''un autre type — { [K in keyof T]: newType }. Base de nombreux utility types comme Readonly<T> et Partial<T>","Un type qui mappe les valeurs à runtime","Un type de dictionnaire"],"correctIndex":1,"explanation":"type Nullable<T> = { [K in keyof T]: T[K] | null }. Les modificateurs +/- permettent d''ajouter/retirer readonly et ?. Ex: type Mutable<T> = { -readonly [K in keyof T]: T[K] }."}]',
  12, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
  questions = EXCLUDED.questions, "timeLimit" = EXCLUDED."timeLimit", "isActive" = true, "updatedAt" = NOW();

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'Next.js', 'Next.js — App Router & Rendu',
  'Server Components, routing, data fetching, optimisations.', 'INTERMEDIATE',
  '[{"id":"nx1","text":"Quelle est la différence entre un Server Component et un Client Component dans Next.js ?","options":["Ils sont identiques","Server Components s''exécutent côté serveur (accès DB direct, pas de JS envoyé au client). Client Components s''exécutent côté client (useState, useEffect, event handlers). Défaut : Server.","Client Components sont plus performants","Server Components peuvent utiliser useState"],"correctIndex":1,"explanation":"Server Components réduisent le JS bundle envoyé au client et permettent l''accès direct aux ressources serveur. Client Components nécessitent ''use client'' en tête de fichier."},{"id":"nx2","text":"Qu''est-ce que le App Router vs Pages Router ?","options":["Le même système avec un nom différent","App Router (app/) : Server Components par défaut, nested layouts, Server Actions, streaming. Pages Router (pages/) : ancien système, tout est Client Component, getServerSideProps/getStaticProps","Pages Router est plus récent","App Router n''est pas en production"],"correctIndex":1,"explanation":"App Router est la direction future de Next.js. Il apporte les React Server Components, les nested layouts partagés, le streaming avec Suspense, et les Server Actions pour les mutations."},{"id":"nx3","text":"Qu''est-ce qu''un layout.tsx dans l''App Router ?","options":["Un fichier CSS spécial","Un composant Server Component qui enveloppe les pages enfants — persistant entre les navigations (ne re-render pas). Permet de partager des UI (navbar, sidebar) entre routes","Un composant qui remplace _app.tsx","Un fichier de configuration"],"correctIndex":1,"explanation":"Les layouts sont imbriqués selon l''arborescence de dossiers. RootLayout (app/layout.tsx) est obligatoire et contient <html> et <body>. Les layouts ne remontent pas l''état lors de la navigation."},{"id":"nx4","text":"Comment fonctionne le data fetching dans les Server Components ?","options":["Seulement avec useSWR ou React Query","Directement avec fetch() dans le composant async — Next.js étend fetch avec cache et revalidate. Les composants async/await sont natifs dans les Server Components","Seulement avec getServerSideProps","Avec useEffect uniquement"],"correctIndex":1,"explanation":"async function Page() { const data = await fetch(''/api/...'', { next: { revalidate: 3600 } }); ... }. Plus besoin de getStaticProps/getServerSideProps dans l''App Router."},{"id":"nx5","text":"Qu''est-ce qu''une Server Action ?","options":["Une route API classique","Une fonction async côté serveur marquée ''use server'' appelable directement depuis les composants (forms, event handlers) — mutations sécurisées sans créer de route API","Un middleware Next.js","Un Server Component avec des effets de bord"],"correctIndex":1,"explanation":"Server Actions permettent les mutations form-first : <form action={myServerAction}>. Elles peuvent être importées dans les Client Components. Next.js gère la sérialisation et la sécurité CSRF."},{"id":"nx6","text":"Que fait `generateStaticParams()` ?","options":["Génère des paramètres pour les tests","Définit les paramètres de routes dynamiques à pré-générer au build time (remplace getStaticPaths dans l''App Router) — ex: toutes les pages /blog/[slug]","Génère des types TypeScript","Configure les paramètres de cache"],"correctIndex":1,"explanation":"export async function generateStaticParams() { return posts.map(p => ({ slug: p.slug })) }. Next.js pré-génère ces pages. Les autres slugs sont rendus dynamiquement ou retournent 404."},{"id":"nx7","text":"Qu''est-ce que l''Image component de Next.js et ses avantages ?","options":["Un composant <img> standard","Un composant optimisé qui : convertit en WebP/AVIF automatiquement, lazy-load, évite le CLS via width/height, sert le bon format et taille selon l''appareil","Un composant pour les images en background","Un wrapper CSS uniquement"],"correctIndex":1,"explanation":"next/image gère : optimisation format (WebP/AVIF), responsive srcset, lazy loading natif, placeholder blur, et sert les images depuis le CDN Next.js. Améliore les Core Web Vitals (LCP, CLS)."},{"id":"nx8","text":"Comment fonctionne le cache dans Next.js App Router ?","options":["Pas de cache par défaut","4 niveaux : Request Memoization (même requête dans un rendu), Data Cache (fetch persistant entre requêtes), Full Route Cache (pages statiques au build), Router Cache (client-side navigation)","Seulement le cache HTTP standard","Cache uniquement configurable dans next.config"],"correctIndex":1,"explanation":"fetch({ cache: ''force-cache'' }) = Data Cache permanent. fetch({ next: { revalidate: n } }) = ISR. fetch({ cache: ''no-store'' }) = dynamique. revalidatePath() et revalidateTag() pour invalider."},{"id":"nx9","text":"Qu''est-ce que le Middleware dans Next.js ?","options":["Un plugin Node.js","Code qui s''exécute avant la requête — s''exécute sur l''Edge Runtime (très rapide), permet : redirection, réécriture d''URL, auth checks, A/B testing, i18n","Un composant serveur spécial","Une configuration de cache"],"correctIndex":1,"explanation":"middleware.ts à la racine. Matcher config pour cibler les routes. S''exécute sur Vercel Edge Network avant le cache — idéal pour l''authentification et les redirections sans cold start."},{"id":"nx10","text":"Qu''est-ce que l''Incremental Static Regeneration (ISR) ?","options":["Un rechargement automatique en développement","Regénération des pages statiques en arrière-plan après un délai (revalidate) — combine les avantages du statique (performance) et du dynamique (données fraîches)","Une migration automatique vers l''App Router","Un système de cache Redis"],"correctIndex":1,"explanation":"fetch(url, { next: { revalidate: 60 } }) → la page est régénérée max toutes les 60s. La première requête après expiration reçoit l''ancienne page et déclenche la régénération en background."}]',
  12, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
  questions = EXCLUDED.questions, "timeLimit" = EXCLUDED."timeLimit", "isActive" = true, "updatedAt" = NOW();

INSERT INTO quizzes (id, skill, title, description, difficulty, questions, "timeLimit", "isActive", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid(), 'MongoDB', 'MongoDB — NoSQL & Agrégations',
  'Documents, requêtes, indexes, agrégations, modélisation.', 'INTERMEDIATE',
  '[{"id":"mg1","text":"Quelle est la différence entre un document MongoDB et une ligne SQL ?","options":["Ils sont identiques","Un document MongoDB est un objet JSON flexible (BSON) sans schéma fixe, pouvant contenir des sous-documents et tableaux imbriqués. Une ligne SQL a un schéma fixe avec des types définis","MongoDB est plus lent","MongoDB ne supporte pas les requêtes complexes"],"correctIndex":1,"explanation":"BSON (Binary JSON) supporte plus de types que JSON (ObjectId, Date, Binary, Decimal128). La flexibilité du schéma permet l''évolution sans migrations — mais nécessite une discipline de modélisation."},{"id":"mg2","text":"Quand choisir l''embedding vs le referencing pour modéliser des relations ?","options":["Toujours utiliser l''embedding","Embedding : données souvent accédées ensemble, relation 1-à-peu. Referencing : données accédées indépendamment, relation N-à-N, documents volumineux ou fréquemment mis à jour séparément","Toujours utiliser le referencing comme en SQL","MongoDB ne supporte pas les relations"],"correctIndex":1,"explanation":"Pattern embedding : un post avec ses commentaires dans le même document. Pattern referencing : users et orders séparés avec userId. L''objectif : accéder aux données en une seule requête."},{"id":"mg3","text":"Qu''est-ce que l''Aggregation Pipeline ?","options":["Un outil de migration de données","Une séquence de stages qui transforment les documents : $match (filtre), $group (agrégation), $project (reshape), $lookup (join), $sort, $limit, $unwind (décompose les arrays)","Une alternative aux indexes","Un type de requête de lecture simple"],"correctIndex":1,"explanation":"db.orders.aggregate([$match: {status:''active''}], [$group: {_id:''$userId'', total:{$sum:''$amount''}}]). Plus puissant que les requêtes simples pour les analytics et les transformations complexes."},{"id":"mg4","text":"Qu''est-ce qu''un index MongoDB et quels types existent ?","options":["Une table de métadonnées","Structure qui accélère les requêtes. Types : Single Field, Compound, Multikey (arrays), Text (full-text search), Geospatial (2dsphere), Hashed, TTL (expiration automatique)","Une vue matérialisée","Un type de collection spéciale"],"correctIndex":1,"explanation":"Index TTL : db.logs.createIndex({createdAt:1},{expireAfterSeconds:86400}) supprime automatiquement les documents après 24h. Index Text : $text:{$search:''...''}. Compound indexes : couvrir plusieurs champs."},{"id":"mg5","text":"Qu''est-ce que le $lookup stage dans l''aggregation pipeline ?","options":["Une recherche full-text","Un équivalent du LEFT OUTER JOIN SQL — joint des documents d''une autre collection basé sur une correspondance de champs","Une opération de mise à jour","Un filtre sur les arrays"],"correctIndex":1,"explanation":"$lookup: { from: ''users'', localField: ''userId'', foreignField: ''_id'', as: ''user'' }. MongoDB 3.6+ supporte les $lookup avec pipeline (join conditionnel plus complexe)."},{"id":"mg6","text":"Qu''est-ce que les transactions multi-documents dans MongoDB ?","options":["MongoDB ne supporte pas les transactions","Depuis MongoDB 4.0, les transactions ACID multi-documents et multi-collections sont supportées — mêmes garanties qu''en SQL dans un replica set ou sharded cluster","Les transactions ne fonctionnent que sur une collection","Les transactions sont automatiques"],"correctIndex":1,"explanation":"session.startTransaction(); db.accounts.updateOne(...); db.transfers.insertOne(...); session.commitTransaction(). Utiliser avec parcimonie — plus lent que les opérations single-document."},{"id":"mg7","text":"Qu''est-ce que le Change Streams ?","options":["Un outil de migration","API permettant aux applications de s''abonner aux changements temps-réel d''une collection, base de données ou cluster — basé sur l''oplog du replica set","Un type de cursor","Une méthode de backup"],"correctIndex":1,"explanation":"collection.watch([{$match:{operationType:''insert''}}]).on(''change'', handler). Utilisé pour la synchronisation temps-réel, les notifications, et l''invalidation de cache. Nécessite un replica set."},{"id":"mg8","text":"Quelle est la stratégie de sharding dans MongoDB ?","options":["MongoDB ne supporte pas le sharding","Distribution horizontale des données sur plusieurs shards via une shard key. Stratégies : Range (plages de valeurs), Hash (distribution uniforme), Zone (géographie)","Sharding = réplication","Le sharding est automatique sans configuration"],"correctIndex":1,"explanation":"La shard key est critique — une mauvaise clé crée du hot spotting. Hash sharding distribue uniformément mais ne supporte pas les range queries. Mongos route les requêtes vers les bons shards."},{"id":"mg9","text":"Qu''est-ce que l''opérateur `$expr` dans les requêtes MongoDB ?","options":["Un opérateur de comparaison classique","Permet d''utiliser des expressions d''aggregation dans les requêtes find() — compare des champs entre eux ou utilise des opérateurs d''agrégation dans un filtre","Un opérateur de mise à jour","Un opérateur géospatial"],"correctIndex":1,"explanation":"db.orders.find({$expr: {$gt: [''$amount'', ''$minAmount'']}}) compare deux champs du même document. Impossible avec les opérateurs de comparaison standard."},{"id":"mg10","text":"Qu''est-ce que Mongoose et quand l''utiliser ?","options":["Un client MongoDB officiel","Un ODM (Object Document Mapper) pour Node.js — ajoute la validation de schéma, les middlewares (hooks), les méthodes virtuelles et les populations (références) par-dessus le driver natif","Un outil de visualisation MongoDB","Un shell MongoDB"],"correctIndex":1,"explanation":"Mongoose apporte la structure (schémas, validation) et la DX (populate, virtuals, pre/post hooks). Peut être over-engineered pour des cas simples. Le driver natif MongoDB est plus performant et flexible."}]',
  12, true, NOW(), NOW()
)
ON CONFLICT (skill) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, difficulty = EXCLUDED.difficulty,
